p_attached_file','2026/07/dandy-and-barry-police.png'),(2992,502,'_wp_attachment_metadata','a:6:{s:5:\"width\";i:560;s:6:\"height\";i:310;s:4:\"file\";s:34:\"2026/07/dandy-and-barry-police.png\";s:8:\"filesize\";i:261411;s:5:\"sizes\";a:2:{s:6:\"medium\";a:5:{s:4:\"file\";s:34:\"dandy-and-barry-police-300x166.png\";s:5:\"width\";i:300;s:6:\"height\";i:166;s:9:\"mime-type\";s:9:\"image/png\";s:8:\"filesize\";i:74759;}s:9:\"thumbnail\";a:5:{s:4:\"file\";s:34:\"dandy-and-barry-police-193x108.png\";s:5:\"width\";i:193;s:6:\"height\";i:108;s:9:\"mime-type\";s:9:\"image/png\";s:8:\"filesize\";i:36138;}}s:10:\"image_meta\";a:13:{s:8:\"aperture\";s:1:\"0\";s:6:\"credit\";s:0:\"\";s:6:\"camera\";s:0:\"\";s:7:\"caption\";s:0:\"\";s:17:\"created_timestamp\";s:1:\"0\";s:9:\"copyright\";s:0:\"\";s:12:\"focal_length\";s:1:\"0\";s:3:\"iso\";s:1:\"0\";s:13:\"shutter_speed\";s:1:\"0\";s:5:\"title\";s:0:\"\";s:11:\"orientation\";s:1:\"0\";s:8:\"keywords\";a:0:{}s:3:\"alt\";s:0:\"\";}}'),(2993,502,'_source_url','https://musicgames.io/data/image/game/dandy-and-barry-police.png'),(2994,502,'_wg_original_image_url','https://musicgames.io/data/image/game/dandy-and-barry-police.png'),(2995,503,'rank_math_internal_links_processed','1'),(2996,503,'source_type','iframe'),(2997,503,'_source_type','field_webgames_source_type'),(2998,503,'iframe_url','https://st.8games.net/7/8g/igra-dendi-i-barri-politsiya/'),(2999,503,'_iframe_url','field_webgames_iframe_url'),(3000,502,'_wp_old_slug','dandy-and-barry-police'),(3001,503,'game_cover','502'),(3002,503,'_game_cover','field_webgames_game_cover'),(3003,503,'_thumbnail_id','502'),(3004,503,'_wg_scraped_source_url','https://musicgames.io/dandy-and-barry-police'),(3005,503,'_wg_original_iframe_url','https://st.8games.net/7/8g/igra-dendi-i-barri-politsiya/'),(3006,503,'_edit_lock','1784528843:1'),(3007,503,'wg_views','1');
